package com.jdmedia.controller;
import com.jdmedia.model.*;import com.jdmedia.service.AppContext;import javafx.concurrent.Task;import javafx.fxml.FXML;import javafx.scene.control.*;import javafx.stage.DirectoryChooser;import java.io.File;import java.nio.file.Path;
public final class ConversionController {private final AppContext context;private Task<Void> task;private Path output;@FXML private Label currentFileLabel,percentLabel,encoderLabel;@FXML private ProgressBar progressBar;@FXML private Button cancelButton,startButton;@FXML private TextField destinationField;@FXML private CheckBox deleteOriginals;public ConversionController(AppContext context){this.context=context;}@FXML public void initialize(){String saved=FolderController.type()==MediaType.MOVIES?context.settings().get().moviesOutputFolder:context.settings().get().seriesOutputFolder;destinationField.setText(saved);currentFileLabel.setText("Selecciona una carpeta de destino para comenzar.");percentLabel.setText("");encoderLabel.setText(context.conversion().supportsNvenc()?"Aceleración NVIDIA NVENC disponible":"NVENC no disponible: se usará el codificador por CPU.");}@FXML private void chooseDestination(){DirectoryChooser chooser=new DirectoryChooser();chooser.setTitle("Selecciona la carpeta de destino");if(!destinationField.getText().isBlank()){File f=new File(destinationField.getText());if(f.isDirectory())chooser.setInitialDirectory(f);}File selected=chooser.showDialog(destinationField.getScene().getWindow());if(selected!=null){output=selected.toPath();destinationField.setText(output.toString());}}@FXML private void start(){try{if(destinationField.getText().isBlank())throw new IllegalArgumentException("Selecciona una carpeta de destino.");output=output==null?Path.of(destinationField.getText()):output;if(FolderController.type()==MediaType.MOVIES)context.settings().get().moviesOutputFolder=output.toString();else context.settings().get().seriesOutputFolder=output.toString();context.settings().save();ConversionOptions base=SummaryController.options();ConversionOptions options=new ConversionOptions(base.preset(),base.crf(),base.audioStreamIndexes(),base.subtitles(),deleteOriginals.isSelected());task=context.conversion().createTask(AnalysisController.media(),options,output);currentFileLabel.textProperty().bind(task.messageProperty());progressBar.progressProperty().bind(task.progressProperty());task.progressProperty().addListener((o,a,b)->{double value=b.doubleValue();context.status().setProgress(value);percentLabel.setText(value<0?"Preparando…":String.format("%.0f %%",value*100));});startButton.setDisable(true);task.setOnSucceeded(e->{context.status().clearProgress();context.status().info("Conversión finalizada.");context.navigation().show("result-view.fxml");});task.setOnFailed(e->{context.status().clearProgress();String detail=task.getException().getMessage();context.status().error(detail);Alert alert=new Alert(Alert.AlertType.ERROR);alert.setTitle("Error de conversión");alert.setHeaderText("NVENC no pudo convertir el archivo");alert.setContentText(detail);alert.getDialogPane().setPrefWidth(850);alert.showAndWait();});new Thread(task,"media-conversion").start();}catch(Exception e){context.status().error(e.getMessage());}}@FXML private void cancel(){if(task!=null)task.cancel(true);context.status().clearProgress();context.status().info("Conversión cancelada.");context.navigation().show("home-view.fxml");}}
